// ── Verify Shopify HMAC ──────────────────────────────────────────────────────
const crypto = require('crypto');
const query = $input.item.json.query || {};
const { hmac, ...restParams } = query;
const apiSecret = $env.SHOPIFY_API_SECRET;
const appKey    = $env.SHOPIFY_APP_KEY;
const returnUrl = $env.SHOPIFY_SETUP_RETURN_URL; // e.g. https://yourapp.com/setup.html

if (!apiSecret) $execution.abort({ message: 'SHOPIFY_API_SECRET env var not set' });
if (!appKey)    $execution.abort({ message: 'SHOPIFY_APP_KEY env var not set' });
if (!returnUrl) $execution.abort({ message: 'SHOPIFY_SETUP_RETURN_URL env var not set' });
if (!hmac)      $execution.abort({ message: 'Missing HMAC parameter' });
if (!query.code) $execution.abort({ message: 'Missing code parameter' });
if (!query.shop) $execution.abort({ message: 'Missing shop parameter' });

// Build sorted message string (all params except hmac)
const message = Object.keys(restParams)
  .sort()
  .map(k => `${k}=${restParams[k]}`)
  .join('&');

const expectedHmac = crypto.createHmac('sha256', apiSecret).update(message).digest('hex');

// Constant-time comparison to prevent timing attacks
if (!crypto.timingSafeEqual(Buffer.from(expectedHmac, 'hex'), Buffer.from(hmac, 'hex'))) {
  $execution.abort({ message: 'HMAC verification failed — request may be tampered' });
}

return [{ json: {
  code:      query.code,
  shop:      query.shop,
  state:     query.state || '',
  appKey,
  apiSecret,
  returnUrl,
  hmacValid: true
} }];

const exch = $input.item.json;
const prev = $('Verify HMAC').item.json;
if (!exch.access_token) $execution.abort({ message: 'Token exchange failed: ' + JSON.stringify(exch) });
return [{ json: {
  access_token: exch.access_token,
  scope:        exch.scope || '',
  shop:         prev.shop,
  state:        prev.state,
  returnUrl:    prev.returnUrl
} }];

const shopData = $input.item.json.shop || {};
const prev = $('Extract Token').item.json;
const state = prev.state || '';
// If state starts with 'dashboard', return to dashboard.html instead of setup.html
const setupUrl = prev.returnUrl;
const returnUrl = state.startsWith('dashboard') ? setupUrl.replace('setup.html','dashboard.html') : setupUrl;
const params = new URLSearchParams({
  shopify_connected: '1',
  token:     prev.access_token,
  shop:      prev.shop,
  shop_name: shopData.name || prev.shop,
  state:     state
});
const redirectTo = `${returnUrl}?${params.toString()}`;
return [{ json: { redirectTo, shopName: shopData.name || prev.shop, shop: prev.shop } }];
